import{_ as i,o as e,c as s,a2 as t}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"许晓霞","text":"数据产品经理","tagline":"10 年产品经验，6 年半深耕房地产与金融大数据产品，覆盖 BI 看板、埋点治理、To C / To B 与 AI 系统落地。目前开放数据产品经理机会。","actions":[{"theme":"brand","text":"查看代表项目","link":"/projects/"},{"theme":"alt","text":"下载 PDF 简历","link":"/assets/resume-xuxiaoxia.pdf"},{"theme":"alt","text":"联系我","link":"/contact"}]},"features":[{"title":"数据产品与 BI 看板","details":"从业务目标出发，设计指标体系、数据口径、经营驾驶舱、下钻逻辑与复盘流程。","link":"/projects/liduoxing/"},{"title":"行业数据产品体系","details":"长期负责房地产 To C、To B、数据平台和地图决策系统，具备完整商业项目经验。","link":"/projects/lansi/"},{"title":"AI 与知识系统","details":"独立推进紫微斗数数据化解读系统，把传统知识拆成知识库、规则库和已上线系统。","link":"/projects/personal/ziwei-ai-system"}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),l={name:"index.md"};function o(r,a,n,c,d,p){return e(),s("div",null,[...a[0]||(a[0]=[t('<section class="lead-panel"><div><p class="eyebrow">Portfolio Focus</p><h2>我最能被看见的优势</h2><p>我的优势在于把复杂业务从“说不清”推进到“可定义、可协作、可上线、可复盘”，同时兼顾页面、数据、流程和落地结果。</p></div><div class="metric-strip"><div><strong>10 年</strong><span>产品经验，其中 6.5 年数据产品</span></div><div><strong>80 万+</strong><span>C 端小程序累计用户</span></div><div><strong>上百家</strong><span>小房书付费门店</span></div><div><strong>5 类</strong><span>AI / BI / 埋点 / To C / To B 项目证据</span></div></div></section><h2 id="代表项目" tabindex="-1">代表项目 <a class="header-anchor" href="#代表项目" aria-label="Permalink to &quot;代表项目&quot;">​</a></h2><div class="case-grid"><a class="case-card is-featured" href="/projects/lansi/"><span class="case-kicker">Real Estate Data</span><h3>澜思房地产大数据产品体系</h3><p>6 年深度负责房地产大数据产品，覆盖 To C 小程序、To B 决策系统、数据平台与地图可视化，多个商业化项目从 0 到 1 落地。</p><ul><li>一房一万新房小程序累计用户 80 万+</li><li>小房书服务上百家付费中小中介门店</li><li>城市地图服务万科、中原等开发商与经纪公司</li><li>数据中心 / RAS 算法支撑多条产品线底层定价</li></ul></a><a class="case-card" href="/projects/liduoxing/"><span class="case-kicker">Finance Data</span><h3>利多星金融数据产品与数据治理</h3><p>围绕策略产品、投顾服务、客户生命周期、埋点治理和风控客诉场景，搭建 BI 看板、指标口径与数据质量体系。</p><ul><li>私享家 BI 经营驾驶舱与多角色分析路径</li><li>多端埋点验收与数据质量治理体系</li><li>AI 客诉风控与用户分层经营框架</li></ul></a><a class="case-card" href="/projects/personal/ziwei-ai-system"><span class="case-kicker">AI Product · 已上线</span><h3>紫微斗数数据化解读系统</h3><p>将传统文化知识拆解为结构化知识库、规则引擎与 AI 解读链路，独立完成从知识工程到系统上线的全流程。</p><ul><li>知识库 + 规则结构 + AI 解读 + 积分交互系统</li><li>线上地址：ziweimodel.cn</li></ul></a></div><h2 id="能力主线" tabindex="-1">能力主线 <a class="header-anchor" href="#能力主线" aria-label="Permalink to &quot;能力主线&quot;">​</a></h2><div class="portfolio-grid"><div class="portfolio-card"><h3>复杂业务产品化</h3><p>把房地产、金融、命理等高上下文业务拆成角色、流程、指标、页面、规则和协作接口。</p></div><div class="portfolio-card"><h3>数据口径与看板设计</h3><p>从经营问题出发定义指标、数据源、筛选条件、下钻路径、验收口径和复盘机制。</p></div><div class="portfolio-card"><h3>AI 协作与系统落地</h3><p>使用 AI 编程、Markdown 知识库和结构化规则，把想法推进到可运行、可上线的完整系统。</p></div><div class="portfolio-card"><h3>长期知识资产沉淀</h3><p>用 Obsidian、Quartz、文档站和项目库持续整理经验，让简历、作品集和个人知识库互相支撑。</p></div></div><h2 id="推荐阅读路径" tabindex="-1">推荐阅读路径 <a class="header-anchor" href="#推荐阅读路径" aria-label="Permalink to &quot;推荐阅读路径&quot;">​</a></h2><ol><li><a href="/projects/">项目作品总览</a>：快速了解代表项目和展示策略。</li><li><a href="/projects/personal/ziwei-ai-system.html">紫微斗数数据化解读系统</a>：看近期知识工程、AI 协作和个人系统落地能力。</li><li><a href="/projects/liduoxing/">利多星金融数据产品</a>：看当前求职方向相关的数据产品能力。</li><li><a href="/projects/lansi/">澜思房地产大数据产品</a>：看长期商业项目经验和硬成果。</li><li><a href="/resume.html">在线简历</a>：查看完整经历与联系方式。</li></ol>',7)])])}const f=i(l,[["render",o]]);export{u as __pageData,f as default};
